from swift.utils import download_ms_file, get_logger, get_seed, safe_ddp_context
from .preprocessor import DATASET_TYPE, AutoPreprocessor
from .utils import sample_dataset

PreprocessFunc = Callable[..., DATASET_TYPE]
logger = get_logger()

